import{_ as t}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as a,c as o,a as r}from"./chunks/runtime-core.esm-bundler.DWBnY2hA.js";const m=JSON.parse('{"title":"Аудио-реактив — визуализатор музыки на WebGPU","description":"Как устроен Аудио-реактив: DSP-ядро на C/WASM, до 500k частиц на WebGPU, режимы Fluid/Cymatics/Nova и автопереключение по битовой сетке. Музыка, которую видно.","frontmatter":{"title":"Аудио-реактив — визуализатор музыки на WebGPU","description":"Как устроен Аудио-реактив: DSP-ядро на C/WASM, до 500k частиц на WebGPU, режимы Fluid/Cymatics/Nova и автопереключение по битовой сетке. Музыка, которую видно.","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/projects/ar-engine"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:title","content":"Аудио-реактив — визуализатор музыки на WebGPU"}],["meta",{"property":"og:description","content":"Как устроен Аудио-реактив: DSP-ядро на C/WASM, до 500k частиц на WebGPU, режимы Fluid/Cymatics/Nova и автопереключение по битовой сетке. Музыка, которую видно."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/projects/ar-engine"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Аудио-реактив — визуализатор музыки на WebGPU"}],["meta",{"name":"twitter:description","content":"Как устроен Аудио-реактив: DSP-ядро на C/WASM, до 500k частиц на WebGPU, режимы Fluid/Cymatics/Nova и автопереключение по битовой сетке. Музыка, которую видно."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}]]},"headers":[],"relativePath":"projects/ar-engine.md","filePath":"projects/ar-engine.md"}'),n={name:"projects/ar-engine.md"};function i(l,e,s,c,d,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="аудио-реактив-—-музыка-которую-видно" tabindex="-1">Аудио-реактив — музыка, которую видно <a class="header-anchor" href="#аудио-реактив-—-музыка-которую-видно" aria-label="Permalink to &quot;Аудио-реактив — музыка, которую видно&quot;">​</a></h1><p><strong>Аудио-реактив</strong> — это визуализатор музыки, который полностью работает в браузере: никакого сервера, загрузки файлов на чужие диски или установки. Бросаете трек (или целую папку) в окно, и музыка превращается в живую графику — облака плазмы, узоры Хладни или пульсирующую «радужку», которая расширяет зрачок на каждый удар.</p><p>→ <strong><a href="/ar/" target="_self">Открыть живое демо</a></strong> (нужен Chrome 113+ с поддержкой WebGPU)</p><h2 id="зачем" tabindex="-1">Зачем <a class="header-anchor" href="#зачем" aria-label="Permalink to &quot;Зачем&quot;">​</a></h2><p>Я инженер и музыкант, и мне давно хотелось не просто слышать звук, а <em>видеть</em> его структуру: где бас, где атака, насколько «яркий» тембр в данный момент. Большинство визуализаторов реагируют на одну общую громкость. Хотелось честного частотного анализа в реальном времени — и чтобы это можно было запустить с любого устройства, не доверяя свою музыку облаку. Отсюда два жёстких ограничения проекта: всё считается локально, и всё работает на нативных браузерных API без CDN.</p><h2 id="как-это-устроено" tabindex="-1">Как это устроено <a class="header-anchor" href="#как-это-устроено" aria-label="Permalink to &quot;Как это устроено&quot;">​</a></h2><p>Движок разделён на два слоя, которые общаются через компактный вектор признаков.</p><h3 id="_1-dsp-ядро-на-c-→-wasm" tabindex="-1">1. DSP-ядро на C → WASM <a class="header-anchor" href="#_1-dsp-ядро-на-c-→-wasm" aria-label="Permalink to &quot;1. DSP-ядро на C → WASM&quot;">​</a></h3><p>Анализ звука написан на чистом C и собирается в <code>engine.wasm</code> через Emscripten. Каждый кадр в ядро уходит блок PCM-сэмплов, а наружу отдаётся структура <code>AudioFrame</code> — плоский массив из 13 чисел с плавающей точкой, который JS читает прямо из WASM-кучи:</p><ul><li>радикс-2 <strong>FFT</strong> → спектр магнитуд;</li><li><strong>4 полосы</strong> RMS-огибающих: sub (20–80 Гц), bass (80–250), mid (250–4000), high (4000–16000);</li><li>детектор битов по <strong>спектральному потоку</strong> + оценка BPM;</li><li>спектральные дескрипторы: <strong>centroid</strong> (яркость тембра) и <strong>tonalness</strong> (тональность против шума).</li></ul><p>ABI устроен по принципу «только добавлять поля в конец» — так все существующие смещения в JS-куче остаются валидными при расширении. Это позволяет наращивать признаки, не ломая бридж. Сами дескрипторы — чистые функции спектра, поэтому покрыты нативными C-юнит-тестами (их можно собрать обычным <code>cc</code>, без Emscripten).</p><h3 id="_2-рендер-на-webgpu" tabindex="-1">2. Рендер на WebGPU <a class="header-anchor" href="#_2-рендер-на-webgpu" aria-label="Permalink to &quot;2. Рендер на WebGPU&quot;">​</a></h3><p>Графику считает GPU. Симуляция гоняет <strong>до 500 000 частиц</strong> через compute-шейдеры на WGSL:</p><ul><li><code>particles_update.wgsl</code> — компьют-проход с тремя силовыми полями (vortex / chladni / nova);</li><li><code>particles_draw.wgsl</code> — аддитивная отрисовка точек;</li><li><code>render.wgsl</code> — тонмаппинг, палитра и финальная тонировка.</li></ul><p>Поверх лежит <strong>обратная связь</strong> (ping-pong текстуры): след частиц затухает с настраиваемым коэффициентом, создавая шлейфы и «дыхание» картинки в такт музыке.</p><p>Вместо упрощённого 2D-фолбэка движок честно требует WebGPU, но <strong>деградирует по мощности GPU</strong>: рендерер определяет класс адаптера (Apple Silicon и дискретные NVIDIA/AMD → high, встроенная Intel → low) и масштабирует число частиц — 150k / 300k / 500k. В тишине цикл дросселируется до ~20 fps, чтобы зря не греть GPU.</p><h2 id="режимы-и-автопилот" tabindex="-1">Режимы и автопилот <a class="header-anchor" href="#режимы-и-автопилот" aria-label="Permalink to &quot;Режимы и автопилот&quot;">​</a></h2><p>Четыре пресета, каждый со своей палитрой и физикой:</p><ul><li><strong>Fluid</strong> — аврора/плазменное облако, дышащее с музыкой.</li><li><strong>Cymatics</strong> — фигуры Хладни: тёмно-синяя пластина с белыми узловыми линиями.</li><li><strong>Nova</strong> — «радужка глаза»: частицы текут по объёму сферы (ортографическая проекция), яркий лимб возникает естественно из-за уплотнения к краю (<code>sin φ</code>), а удар расширяет зрачок — настоящий эффект мидриаза.</li><li><strong>Auto</strong> — автопилот, переключающий режимы <strong>по музыкальной сетке</strong>.</li></ul><p>Авто-режим — самая интересная часть. Он считает удары по нарастающим фронтам <code>beat_pulse</code> и меняет картинку каждые 4 / 8 / 16 битов (энергичные пассажи — чаще, спокойные — реже). Какой режим включить, подсказывает медленная EMA спектрального профиля: бас тянет к Nova, верх и тишина — к Cymatics, баланс — к Fluid. Для эмбиента и треков с редкими ударами есть запасной таймер от BPM, чтобы картинка не «застывала», а переход всегда идёт через эффект scatter-dissolve — частицы рассыпаются и собираются в новую форму.</p><h2 id="тембр-→-цвет" tabindex="-1">Тембр → цвет <a class="header-anchor" href="#тембр-→-цвет" aria-label="Permalink to &quot;Тембр → цвет&quot;">​</a></h2><p>Отдельный модуль превращает пару дескрипторов <code>(centroid, tonal)</code> в оттенок. Это не классификация инструментов (на 60 fps она нереалистична), а импрессионистская 2D-карта: точки-«якоря» инструментов (мужской/женский голос, струнные, перкуссия, бас) на плоскости, а текущий цвет интерполируется между ними по обратным расстояниям (веса Шепарда). Оттенок усредняется <strong>по кругу</strong> — через единичные векторы и <code>atan2</code>, иначе блендинг ломался бы на стыке 1.0/0.0 цветового круга.</p><h2 id="что-было-сложно" tabindex="-1">Что было сложно <a class="header-anchor" href="#что-было-сложно" aria-label="Permalink to &quot;Что было сложно&quot;">​</a></h2><ul><li><strong>Музыкальные переходы.</strong> Сделать так, чтобы смена режима попадала на фразу, а не на случайный кадр — отсюда битовая сетка с фолбэком по BPM.</li><li><strong>Объёмная Nova.</strong> Заставить плоские частицы читаться как объём глаза: поток по меридианам сферы, затухание задней полусферы (<code>smoothstep</code> по <code>cos</code>), мидриаз на бит. Геометрия продублирована в <code>nova_project.js</code> и покрыта тестами, чтобы JS и WGSL не разъезжались.</li><li><strong>Запись.</strong> Параллельный full-res путь 1920×1080 в оффскрин-канвас, экспорт в <code>.webm</code>; при записи дросселирование отключается, иначе кодировщик «голодает» в тихих местах.</li></ul><h2 id="текущее-состояние" tabindex="-1">Текущее состояние <a class="header-anchor" href="#текущее-состояние" aria-label="Permalink to &quot;Текущее состояние&quot;">​</a></h2><p>Работают все четыре режима, drag-and-drop файлов и папок с плейлистом, захват звука вкладки (например, Яндекс Музыки) через <code>getDisplayMedia</code>, запись в <code>.webm</code>, полноэкранный режим с автоскрытием интерфейса и живая подстройка Nova прямо из консоли. WGSL проверяется по косвенным признакам (чистая сборка, согласованность UBO-разметки, зеркальные JS-тесты) плюс ручной визуальный прогон в Chrome.</p><p>→ Попробовать самому: <strong><a href="/ar/" target="_self">/ar/</a></strong></p><h2 id="из-блога" tabindex="-1">Из блога <a class="header-anchor" href="#из-блога" aria-label="Permalink to &quot;Из блога&quot;">​</a></h2><ul><li><a href="/posts/2021-05-08-paupiauau.html">Новый сингл</a> — музыка, ради которой всё это и затевалось.</li><li><a href="/posts/2020-09-25-critical-rendering-path.html">Critical Rendering Path</a> — как браузер превращает данные в пиксели; фундамент, на котором стоит весь GPU-рендер.</li></ul>',29)])])}const u=t(n,[["render",i]]);export{m as __pageData,u as default};
